describe('POST /checkout', () => {
  let gatewayStub;
  let repositoryStub;
  let emailMock;
  let app;

  beforeEach(() => {
    gatewayStub = {
      cobrar: jest.fn()
    };

    repositoryStub = {
      salvar: jest.fn(async (pedido) => ({
        ...pedido,
        id: 1001
      }))
    };

    emailMock = {
