    const service = new PedidoConsultaService({
      pedidoRepository: pedidoRepositoryStub,
      cache: cacheStub,
      ttlSegundos: 60
    });

    const consultas = Array.from(
      { length: 100 },
      () => service.buscarPorId(1001)
    );

